def particionar_datos(datos, n):
    # tu código aquí
    pass

exercises.solution:
def particionar_datos(datos, n):
    tamanio = len(datos) // n
    resultado = []
    for i in range(n):
        if i == n - 1:
            # La última partición toma el resto de los elementos
            resultado.append(datos[i * tamanio:])
        else:
            resultado.append(datos[i * tamanio : (i + 1) * tamanio])
    return resultado

